import{_ as e,o as r,c as t,ah as i}from"./chunks/framework.C2p4DT9L.js";const b=JSON.parse('{"title":"并发模型","description":"","frontmatter":{"title":"并发模型","order":6},"headers":[],"relativePath":"server/distribute/basic/concurrency/index.md","filePath":"server/distribute/basic/concurrency/index.md"}'),o={name:"server/distribute/basic/concurrency/index.md"};function n(c,a,h,s,l,d){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="并发模型" tabindex="-1">并发模型 <a class="header-anchor" href="#并发模型" aria-label="Permalink to “并发模型”">​</a></h1><p>服务端需要同时处理大量请求，并发模型决定了如何组织多个执行单元（进程、线程、协程）来共享 CPU 时间。</p><h2 id="并发-vs-并行" tabindex="-1">并发 vs 并行 <a class="header-anchor" href="#并发-vs-并行" aria-label="Permalink to “并发 vs 并行”">​</a></h2><p>并发是多个任务在重叠的时间段内启动、运行和完成，但不一定同时进行。并行是多个任务同时进行，需要多核 CPU 支持。</p><h2 id="进程" tabindex="-1">进程 <a class="header-anchor" href="#进程" aria-label="Permalink to “进程”">​</a></h2><p>进程是操作系统资源分配的基本单位，拥有独立的内存空间、文件描述符。进程间通信需要特殊机制：管道、消息队列、共享内存。</p><h3 id="多进程模型" tabindex="-1">多进程模型 <a class="header-anchor" href="#多进程模型" aria-label="Permalink to “多进程模型”">​</a></h3><p>Nginx 的 master-worker 模式，多个 worker 进程监听同一个 socket。Chrome 的多进程架构，每个标签页一个进程。</p><h2 id="线程" tabindex="-1">线程 <a class="header-anchor" href="#线程" aria-label="Permalink to “线程”">​</a></h2><p>线程是 CPU 调度的基本单位，同一进程的线程共享进程的内存空间。线程间通信通过共享内存，但需要同步机制。</p><h3 id="线程安全" tabindex="-1">线程安全 <a class="header-anchor" href="#线程安全" aria-label="Permalink to “线程安全”">​</a></h3><p>互斥锁（Mutex）、读写锁（RWLock）、原子操作（Atomic）、无锁数据结构（Lock-free）。</p><h2 id="协程" tabindex="-1">协程 <a class="header-anchor" href="#协程" aria-label="Permalink to “协程”">​</a></h2><p>协程是用户态的轻量级线程，由运行时调度而非操作系统内核。</p><h3 id="go-goroutine" tabindex="-1">Go goroutine <a class="header-anchor" href="#go-goroutine" aria-label="Permalink to “Go goroutine”">​</a></h3><p>Go goroutine 是有栈协程，初始栈大小 2KB，按需扩容。Goroutine 切换只需要保存三个寄存器，切换开销小。</p><h3 id="async-await" tabindex="-1">async/await <a class="header-anchor" href="#async-await" aria-label="Permalink to “async/await”">​</a></h3><p>async/await 是基于事件循环的异步编程模型。JavaScript、Python、C++ 都支持 async/await。</p><h2 id="事件驱动" tabindex="-1">事件驱动 <a class="header-anchor" href="#事件驱动" aria-label="Permalink to “事件驱动”">​</a></h2><p>事件驱动模型基于 Reactor 模式：事件源产生事件，事件循环监听事件，事件处理器处理事件。</p><h3 id="reactor-模式" tabindex="-1">Reactor 模式 <a class="header-anchor" href="#reactor-模式" aria-label="Permalink to “Reactor 模式”">​</a></h3><p>单 Reactor 单线程：所有事件串行处理。单 Reactor 多线程：Handler 在线程池中执行。主从 Reactor：Main Reactor 负责 accept，Sub Reactor 负责 I/O。</p><h2 id="混合模型" tabindex="-1">混合模型 <a class="header-anchor" href="#混合模型" aria-label="Permalink to “混合模型”">​</a></h2><p>实际系统常采用混合模式：事件循环处理 I/O，线程池处理 CPU 密集任务。Node.js 的 worker_threads 处理 CPU 密集任务。Go 的 goroutine 结合了事件驱动和多线程的优点。</p>',24)])])}const m=e(o,[["render",n]]);export{b as __pageData,m as default};
